#include<iostream>
using namespace std;

double a;
int main (){
    cin >> a;
    int b = a / 100; double b1 = a - b * 100; //求百位数
    int c = b1 / 10; double c1 = b1 - c * 10; //求十位数
    int d = c1 / 1; double d1 = c1 - d; //求个位数
    int e = d1 / 0.1; //求小数点后
    cout << e + d * 0.1 + c * 0.01 + b * 0.001 << endl; // 反转相加
    return 0;
}
